# RFC 9728 metadata endpoint
@app.get("/.well-known/oauth-protected-resource")
def oauth_metadata():
    return {
        "resource": "https://weather-api.example.com",
        "authorization_servers": ["https://auth.example.com"],
        "scopes_supported": ["weather:read", "weather:write"],
        "bearer_methods_supported": ["header"]
    }

# Gateway-level allowlist
ALLOWED_SERVERS = [
    "weather-api.example.com",
    "database-api.example.com"
]

def check_server_allow(server_url: str):
    if server_url not in ALLOWED_SERVERS:
        raise Forbidden(f"Server {server_url} not allowed")
